using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from an external API by its identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to fetch")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search the external API for resources matching a query string.")]
    public async Task<string> SearchResources(
        [Description("The search query to filter resources")] string query,
        [Description("Maximum number of results to return (default: 10)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources with query={Query}, max={Max}", query, maxResults);
        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={maxResults}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific focus or angle.")]
    public static ChatMessage SummarizeWithFocus(
        [Description("The content to summarize")] string content,
        [Description("The specific aspect or angle to focus on")] string focus) =>
        new(ChatRole.User,
            $"Summarize the following content, focusing specifically on {focus}:\n\n{content}");
}

